CREATE OR REPLACE FUNCTION fpb_spec_coll_twin ( as_coll_ref text , adtm_begin timestamp(0) ) RETURNS varchar AS $body$
DECLARE

  ls_rc varchar(1000);
/*หลักทรัพย์ร่วมกัน ใช้ชื่อคนกู้ทั้ง 2 คน ต้องเริ่มสัญญาวันเดียวกัน */

  cur_data CURSOR FOR
    SELECT pka_com_function.fp_get_member_name( sc_lon_m_loan_request.membership_no ) as memname
    from sc_lon_m_req_coll
    ,sc_lon_m_loan_request
    where 1=1
    and sc_lon_m_loan_request.loan_requestment_no = sc_lon_m_req_coll.loan_requestment_no
    and sc_lon_m_req_coll.ref_own_no = as_coll_ref
    and sc_lon_m_loan_request.begining_of_contract = adtm_begin
    order by sc_lon_m_loan_request.loan_requestment_no
;

  type tabi_data is table of cur_data%rowtype index by integer;ltabi_data tabi_data;
  li_count integer;

BEGIN
  open cur_data;fetch cur_data bulk collect into ltabi_data;close cur_data;
  li_count := ltabi_data.count;

  --ไม่มีคำขอ อาจจะเป็นสัญญาเก่าๆ
  if li_count = 0 then
    select pka_com_function.fp_get_member_name( membership_no ) into STRICT ls_rc
    from  sc_lon_req_coll_law_head
    where doc_no = as_coll_ref;
    return ls_rc;
  end if;

  for i in 1..li_count loop
    if i > 1 then
      ls_rc := ls_rc||' และ ';
    end if;

      ls_rc := ls_rc||trim(both ltabi_data[i].memname);
  end loop;
  return  ls_rc;
exception when others then return null;
end;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
